import pytest
from datetime import date, timedelta

@pytest.mark.parametrize("start_date,expected_status", [
    ((date.today() - timedelta(days=1)).isoformat(), 422),
    (date.today().isoformat(), 422),
    ("", 422),
    (None, 422),
    ("not-a-date", 422),
])
def test_standing_order_decision_table_all_invalid_date_forms(
    auth_client, valid_order_payload, start_date, expected_status
):
    payload = valid_order_payload(start_date=start_date)
    resp = auth_client.post("/standing-orders", json=payload)
    assert resp.status_code in (400, 422)
    if start_date in (
        (date.today() - timedelta(days=1)).isoformat(),
        date.today().isoformat(),
    ):
        assert resp.status_code == expected_status
